$urls = @('http://localhost:5100/','http://localhost:5101/healthz','http://localhost:5102/healthz','http://localhost:5103/healthz','http://localhost:5104/healthz','http://localhost:5105/healthz','http://localhost:5110/healthz','http://localhost:5110/api/gateway/customer/branches')
foreach($url in $urls){ try { $r = Invoke-WebRequest -Uri $url -UseBasicParsing -TimeoutSec 10; Write-Output "OK $url => $($r.StatusCode)"; $c=$r.Content; if($c.Length -gt 160){$c=$c.Substring(0,160)}; Write-Output $c } catch { Write-Output "FAIL $url => $($_.Exception.Message)" } ; Write-Output '---' }
